import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.filter.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.reduce.js";
import axios from 'axios';
export default {
  name: 'CommunityEvents',
  data() {
    return {
      loading: false,
      eventList: [],
      total: 0,
      currentPage: 1,
      pageSize: 10,
      filterForm: {
        search: '',
        status: '',
        is_pinned: '',
        date_range: ''
      },
      statistics: {
        totalEvents: 0,
        activeEvents: 0,
        upcomingEvents: 0,
        totalParticipants: 0
      },
      detailDialogVisible: false,
      currentEvent: null,
      // 创建活动相关
      createDialogVisible: false,
      createForm: {
        title: '',
        description: '',
        location: '',
        start_date: '',
        end_date: '',
        prize_info: '',
        is_pinned: false,
        status: 'upcoming'
      },
      imageUrl: '',
      uploadLoading: false
    };
  },
  created() {
    this.loadData();
    this.loadStatistics();
    this.handleUrlParams();
  },
  watch: {
    $route: {
      handler: 'handleUrlParams',
      immediate: true
    }
  },
  methods: {
    handleUrlParams() {
      // 处理URL参数，从Dashboard页面跳转过来时自动打开详情
      const editId = this.$route.query.edit;
      if (editId) {
        const event = this.eventList.find(e => e.id === parseInt(editId));
        if (event) {
          this.viewEvent(event);
        } else {
          // 如果事件还没加载，延迟一下再查找
          setTimeout(() => {
            const event = this.eventList.find(e => e.id === parseInt(editId));
            if (event) {
              this.viewEvent(event);
            }
          }, 1000);
        }
        // 清除URL参数
        this.$router.replace({
          query: {}
        });
      }
    },
    async loadData() {
      this.loading = true;
      try {
        const params = {
          page: this.currentPage,
          page_size: this.pageSize,
          search: this.filterForm.search,
          status: this.filterForm.status,
          is_pinned: this.filterForm.is_pinned
        };
        const response = await axios.get('/admin-api/community/events/', {
          params
        });
        if (response.data) {
          // 处理标准 DRF 分页格式
          if (response.data.results !== undefined) {
            this.eventList = response.data.results || [];
            this.total = response.data.count || 0;
          } else {
            // 处理可能的数组格式
            this.eventList = Array.isArray(response.data) ? response.data : response.data.data || [];
            this.total = this.eventList.length;
          }
        } else {
          this.eventList = [];
          this.total = 0;
        }
      } catch (error) {
        this.eventList = [];
        this.total = 0;
        // 只在不是取消操作的情况下显示错误消息
        if (error !== 'cancel') {
          this.$message.error('加载数据失败');
        }
      } finally {
        this.loading = false;
      }
    },
    async loadStatistics() {
      try {
        const response = await axios.get('admin-api/community/events/statistics/');
        if (response.data) {
          // 处理可能的认证错误或数据格式
          if (response.data.code === 200) {
            const data = response.data.data || {};
            this.statistics = {
              totalEvents: data.totalEvents || data.total_events || 0,
              activeEvents: data.activeEvents || data.active_events || 0,
              upcomingEvents: data.upcomingEvents || data.upcoming_events || 0,
              totalParticipants: data.totalParticipants || data.total_participants || 0
            };
          } else if (response.data.detail) {
            // 认证错误或其他错误
            // 使用默认值
            this.statistics = {
              totalEvents: this.eventList.length,
              activeEvents: this.eventList.filter(e => e.status === 'active').length,
              upcomingEvents: this.eventList.filter(e => e.status === 'upcoming').length,
              totalParticipants: this.eventList.reduce((sum, e) => sum + (e.participant_count || 0), 0)
            };
          } else {
            // 直接数据格式
            const data = response.data;
            this.statistics = {
              totalEvents: data.totalEvents || data.total_events || 0,
              activeEvents: data.activeEvents || data.active_events || 0,
              upcomingEvents: data.upcomingEvents || data.upcoming_events || 0,
              totalParticipants: data.totalParticipants || data.total_participants || 0
            };
          }
        } else {
          // 使用当前列表数据计算统计
          this.statistics = {
            totalEvents: this.eventList.length,
            activeEvents: this.eventList.filter(e => e.status === 'active').length,
            upcomingEvents: this.eventList.filter(e => e.status === 'upcoming').length,
            totalParticipants: this.eventList.reduce((sum, e) => sum + (e.participant_count || 0), 0)
          };
        }
      } catch (error) {
        // 使用当前列表数据计算统计作为后备
        this.statistics = {
          totalEvents: this.eventList.length,
          activeEvents: this.eventList.filter(e => e.status === 'active').length,
          upcomingEvents: this.eventList.filter(e => e.status === 'upcoming').length,
          totalParticipants: this.eventList.reduce((sum, e) => sum + (e.participant_count || 0), 0)
        };
      }
    },
    handleSearch() {
      this.currentPage = 1;
      this.loadData();
    },
    resetFilter() {
      this.filterForm = {
        search: '',
        status: '',
        is_pinned: '',
        date_range: ''
      };
      this.currentPage = 1;
      this.loadData();
    },
    handleSizeChange(val) {
      this.pageSize = val;
      this.loadData();
    },
    handleCurrentChange(val) {
      this.currentPage = val;
      this.loadData();
    },
    createEvent() {
      this.createDialogVisible = true;
      this.resetCreateForm();
    },
    resetCreateForm() {
      this.createForm = {
        title: '',
        description: '',
        location: '',
        start_date: '',
        end_date: '',
        prize_info: '',
        is_pinned: false,
        status: 'upcoming'
      };
      this.imageUrl = '';
      this.uploadLoading = false;
    },
    handleImageUploadSuccess(response) {
      if (response.data && response.data.url) {
        this.imageUrl = response.data.url;
        this.$message.success('图片上传成功');
      } else {
        this.$message.error('图片上传失败');
      }
      this.uploadLoading = false;
    },
    handleImageUploadError(error) {
      this.$message.error('图片上传失败');
      this.uploadLoading = false;
    },
    beforeImageUpload(file) {
      this.uploadLoading = true;
      const isJPG = file.type === 'image/jpeg' || file.type === 'image/png';
      const isLt2M = file.size / 1024 / 1024 < 2;
      if (!isJPG) {
        this.$message.error('只能上传JPG/PNG图片!');
        this.uploadLoading = false;
        return false;
      }
      if (!isLt2M) {
        this.$message.error('图片大小不能超过2MB!');
        this.uploadLoading = false;
        return false;
      }
      return true;
    },
    async submitCreateForm() {
      if (!this.createForm.title) {
        this.$message.error('请输入活动标题');
        return;
      }
      try {
        const formData = {
          ...this.createForm,
          image: this.imageUrl
        };
        const response = await axios.post('/admin-api/community/events/', formData);
        if (response.data.code === 200) {
          this.$message.success('活动创建成功');
          this.createDialogVisible = false;
          this.loadData();
          this.loadStatistics();
        } else {
          this.$message.error('创建失败: ' + response.data.message);
        }
      } catch (error) {
        console.error('创建活动失败:', error);
        this.$message.error('创建失败，请稍后重试');
      }
    },
    viewEvent(event) {
      this.currentEvent = event;
      this.detailDialogVisible = true;
    },
    editEvent(event) {
      this.$message.info(`编辑活动: ${event.title}`);
    },
    async togglePin(event) {
      try {
        const action = event.is_pinned ? '取消置顶' : '置顶';
        await this.$confirm(`确定要${action}活动 "${event.title}" 吗？`, '确认', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        });
        const response = await axios.post(`/admin-api/community/events/${event.id}/toggle_pin/`);
        if (response.data.code === 200) {
          event.is_pinned = !event.is_pinned;
          this.$message.success(`${action}成功`);
        } else {
          this.$message.error('操作失败: ' + response.data.message);
        }
      } catch (error) {
        if (error !== 'cancel') {
          console.error('切换置顶状态失败:', error);
          this.$message.error('操作失败');
        }
      }
    },
    async toggleStatus(event) {
      try {
        const action = this.getStatusActionText(event.status);
        await this.$confirm(`确定要${action}活动 "${event.title}" 吗？`, '确认', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        });
        const response = await axios.post(`/admin-api/community/events/${event.id}/toggle_status/`);
        if (response.data.code === 200) {
          // 更新本地状态
          const statusTransitions = {
            'active': 'ended',
            'upcoming': 'active',
            'ended': 'upcoming'
          };
          event.status = statusTransitions[event.status] || 'upcoming';
          this.$message.success(`${action}成功`);
        } else {
          this.$message.error('操作失败: ' + response.data.message);
        }
      } catch (error) {
        if (error !== 'cancel') {
          console.error('切换活动状态失败:', error);
          this.$message.error('操作失败');
        }
      }
    },
    async deleteEvent(event) {
      try {
        await this.$confirm(`确定要删除活动 "${event.title}" 吗？此操作不可恢复。`, '确认删除', {
          confirmButtonText: '确定',
          cancelButtonText: '取消',
          type: 'warning'
        });
        const response = await axios.delete(`/admin-api/community/events/${event.id}/`);
        if (response.data.code === 200) {
          this.$message.success('活动删除成功');
          this.loadData();
        } else {
          this.$message.error('删除失败: ' + response.data.message);
        }
      } catch (error) {
        if (error !== 'cancel') {
          console.error('删除活动失败:', error);
          this.$message.error('删除失败');
        }
      }
    },
    refreshData() {
      this.loadData();
      this.loadStatistics();
      this.$message.success('数据已刷新');
    },
    exportEvents() {
      this.$confirm('确定要导出活动数据吗？', '导出数据', {
        confirmButtonText: '确定',
        cancelButtonText: '取消',
        type: 'info'
      }).then(async () => {
        try {
          const response = await axios.get('/admin-api/community/events/export/');
          if (response.data.code === 200) {
            this.$message.success('数据导出成功，请在下载中心查看');
          } else {
            this.$message.error('导出失败: ' + response.data.message);
          }
        } catch (error) {
          console.error('导出数据失败:', error);
          this.$message.error('导出失败，请稍后重试');
        }
      }).catch(() => {
        // 取消导出
      });
    },
    tableRowClassName({
      row
    }) {
      // 根据活动状态设置不同的行样式
      if (row.is_pinned) {
        return 'pinned-row';
      }
      if (row.status === 'active') {
        return 'active-row';
      }
      if (row.status === 'ended') {
        return 'ended-row';
      }
      return '';
    },
    // 辅助方法
    getStatusType(status) {
      const types = {
        'active': 'success',
        'upcoming': 'info',
        'ended': 'danger'
      };
      return types[status] || 'info';
    },
    getStatusText(status) {
      const texts = {
        'active': '进行中',
        'upcoming': '即将开始',
        'ended': '已结束'
      };
      return texts[status] || status;
    },
    getStatusButtonType(status) {
      const types = {
        'active': 'warning',
        'upcoming': 'success',
        'ended': 'primary'
      };
      return types[status] || 'primary';
    },
    getStatusActionText(status) {
      const actions = {
        'active': '结束活动',
        'upcoming': '开始活动',
        'ended': '重新激活'
      };
      return actions[status] || '操作';
    },
    formatDate(dateString) {
      const date = new Date(dateString);
      return date.toLocaleString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
      });
    },
    truncateText(text, maxLength) {
      if (!text) return '';
      return text.length > maxLength ? text.substring(0, maxLength) + '...' : text;
    }
  }
};
